'use client'
import { motion } from 'framer-motion'
import { Plus } from 'lucide-react'
import { useCart } from '@/store/cart'

export function ProductCard({ id, name, price }: { id: string; name: string; price: number }) {
  const add = useCart(s => s.add)
  return (
    <motion.div whileHover={{ scale: 1.02 }} className="p-4 rounded-2xl card flex flex-col gap-3">
      <div className="text-lg font-semibold">{name}</div>
      <div className="text-text-muted">${price.toFixed(2)}</div>
      <motion.button whileHover={{ scale: 1.05, rotate: 4 }} onClick={() => add({ id, name, price })} className="mt-auto px-3 py-2 rounded-xl glass flex items-center gap-2">
        <Plus className="size-4" />
        <span>Quick Add</span>
      </motion.button>
    </motion.div>
  )
}
